import scala.collection.immutable.Set

object Solution {
  /**
   * Given an array nums1 of length n with distinct integers.
   * Construct another array nums2 of length n such that all elements in nums2 are either all odd or all even.
   * For each index i, you must choose one of the following options:
   * - nums2[i] = nums1[i]
   * - nums2[i] = nums1[i] - nums1[j], where j != i
   * If such an array can be constructed, return true; otherwise, return false.
   *
   * @param nums1 The input array.
   * @return True if a valid nums2 can be constructed, false otherwise.
   */
  def nums1(nums1: Array[Long]): Boolean = {
    val n = nums1.length
    if (n == 1) {
      // Any single element array is trivially all odd or all even.
      true
    }

    // We need to check two possibilities:
    // 1. Can we make all nums2 elements even?
    // 2. Can we make all nums2 elements odd?

    // Let's analyze the parity.
    // Parity(nums2[i]) depends on Parity(nums1[i]) and Parity(nums1[j]).
    // Parity(A - B) is:
    // Even - Even = Even
    // Odd - Odd = Even
    // Even - Odd = Odd
    // Odd - Even = Odd

    // We iterate over all possible target parities (0 for even, 1 for odd).
    for (targetParity <- Array(0, 1)) {
      var possible = true

      // For each element i, we check if there exists a choice for nums2[i] 
      // that yields the targetParity.
      for (i <- 0 until n) {
        var canMatchTarget = false

        // Option 1: nums2[i] = nums1[i]
        val parity1 = (nums1(i) % 2).toInt
        if (parity1 == targetParity) {
          canMatchTarget = true
        }

        // Option 2: nums2[i] = nums1[i] - nums1[j], where j != i
        if (!canMatchTarget) {
          for (j <- 0 until n) {
            if (i == j) continue

            // Calculate parity of nums1[i] - nums1[j]
            // (A - B) mod 2 = (A mod 2 - B mod 2) mod 2
            var parity2 = (nums1(i) % 2).toInt - (nums1(j) % 2).toInt
            // Ensure result is in {0, 1}
            if (parity2 < 0) parity2 += 2 

            if (parity2 == targetParity) {
              canMatchTarget = true
              break // Found a suitable j for this i
            }
          }
        }

        if (!canMatchTarget) {
          possible = false
          break // Cannot satisfy the targetParity for this i, so this targetParity fails
        }
      }

      if (possible) {
        return true // Found a successful configuration for at least one target parity
      }
    }

    false // Neither all even nor all odd is possible
  }
}
