      true
    }

    // We need to check if it's possible to make all elements of nums2 even OR all elements of nums2 odd.

    // Parity of a number: 0 for even, 1 for odd.
    val parities1 = nums1.map(_.toInt % 2).toArray

    // Helper function to check if a target parity (0 for even, 1 for odd) is achievable for all elements
    def checkParity(targetParity: Int): Boolean = {
      for (i <- 0 until n) {
        // For each index i, we must be able to choose an option such that nums2[i] has targetParity.
        var possibleForI = false

        // Option 1: nums2[i] = nums1[i]
        val parity1 = parities1(i)
