        if (!possibleForI) {
          for (j <- 0 until n) {
            if (i != j) {
              // Parity of (a - b) is Parity(a) XOR Parity(b)
              // Parity(nums1[i] - nums1[j]) = (parities1(i) + parities1(j)) % 2
              val parity2 = (parities1(i) + parities1(j)) % 2
              if (parity2 == targetParity) {
                possibleForI = true
                break // Found a valid j for this i
              }
            }
          }
        }

        if (!possibleForI) {
          return false // If for any i, we can't achieve the target parity, this target parity fails.
        }
